Drupal.behaviors.textCopyButton={attach(t){t.querySelectorAll(".text-copy-button__button:not([data-text-copy-init])").forEach((t=>{t.setAttribute("data-text-copy-init",""),t.addEventListener("click",(t=>{const e=t.target.closest(".text-copy-button__button");if(!e||!navigator.clipboard)return;const o=e.closest(".text-copy-button");if(!o)return;const n=o.querySelector(".pre-text__text");if(!n)return;const c=n.textContent.trim();navigator.clipboard.writeText(c).then((()=>{const t=new CustomEvent("text-copy-button:copied",{bubbles:!0,cancelable:!0,detail:{text:c,button:e}});e.dispatchEvent(t)&&(e.textContent="Copied to clipboard",setTimeout((()=>{e.textContent="(Copy)"}),1700))})).catch((()=>{e.textContent="(error)"}))}))}))}};